    def write_data(self, meaning):
        if tools.contains_only_digits(self.enter_price_on_buy.text()) or tools.contains_only_digits(self.enter_price_on_sell.text()):
            if meaning == 'buy':
                crypto = self.crypto_buy_box.currentText()
                use_SBP_buy_check = self.use_SBP_buy_check.isChecked()

                card = self.card_for_buy_box.currentText()
                
                price = float(self.enter_price_on_buy.text())
                summ = float(self.summ_on_buy_enter.text())
                quantity = summ / price

                db.set_balance(card, float(summ), 'minus')
                db.set_crypto(crypto, float(quantity), 'plus')
                db.set_balance(card, float(summ), 'turnover')

                if use_SBP_buy_check:
                    db.set_balance(card, float(summ), 'sbp')

            elif meaning == 'sell':
                crypto = self.crypto_sell_box.currentText()
                card = self.card_for_sell_box.currentText()
                price = float(self.enter_price_on_sell.text())
                quantity = float(self.summ_on_sell_enter.text())
                
                summ = price * quantity

                db.set_balance(card, float(summ), 'plus')
                db.set_crypto(crypto, float(quantity), 'minus')
                db.set_balance(card, float(summ), 'turnover')
   
    def update_spred(self, meaning):
        try:
            crypto_buy = self.crypto_buy_box.currentText()
            crypto_sell = self.crypto_sell_box.currentText()
            price_buy = float(self.enter_price_on_buy.text())
            price_sell = float(self.enter_price_on_sell.text())
            if meaning:
                if crypto_buy == crypto_sell:
                    spred = ((price_sell * 100) / price_buy) - 100
                    self.label_2.setText(f'{round(spred, 1)}%')
            else:
                if crypto_buy != crypto_sell:
                    curse, sym = tools.combo_pair(crypto_buy, crypto_sell)
                    if sym:
                        quantity = 1 * curse
                    else:
                        quantity = 1 / curse

                    res = quantity * price_sell
                    spred = ((res * 100) / price_buy) - 100
                    self.label_2.setText(f'{round(spred, 1)}%')
        except Exception as ex: 
            print(ex)

    def money_transfer(self):
        card_forward = self.comboBox_7.currentText()
        card_get = self.comboBox_8.currentText()

        name_bank_forward = db.find_element('cards', ['number_card', card_forward], 'name_bank')
        name_bank_get = db.find_element('cards', ['number_card', card_get], 'name_bank') #tools.find_name_bank(card_get)[0]
        bank_sbp_forward = db.find_element('cards', ['number_card', card_forward], 'turnover_sbp')

        if card_get != card_forward:
            summ = float(self.lineEdit_3.text())
            if name_bank_forward != name_bank_get:
                summ = tools.return_percent(summ, 0.5) if float(bank_sbp_forward) - summ <= 0 else summ
                db.set_balance(card_forward, float(summ), 'minus')
                db.set_balance(card_get, float(summ), 'plus')

                db.set_balance(card_forward, float(summ), 'sbp')

                db.set_balance(card_forward, float(summ), 'turnover')
                db.set_balance(card_get, float(summ), 'turnover')
                
            else:
                db.set_balance(card_forward, float(summ), 'minus')
                db.set_balance(card_get, float(summ), 'plus')

                db.set_balance(card_forward, float(summ), 'turnover')
                db.set_balance(card_get, float(summ), 'turnover')
    
    def set_statistics(self):
        card_name = self.choose_card_box.currentText()
        card_turnover = db.find_element('cards', ['number_card', card_name], 'turnover')
        card_balance = db.find_element('cards', ['number_card', card_name], 'balance')
        card_turnover_SBP = db.find_element('cards', ['number_card', card_name], 'turnover_sbp')

        crypto_data = self.balance_crypto_box.currentText()
        crypto_quantity = db.find_element('crypto', ['name_crypto', crypto_data], 'quantity')

        self.card_turnover_num.setText(f'{card_turnover}р')
        self.balance_card_num.setText(f'{card_balance}р')
        self.turnover_SBP_num.setText(f'{card_turnover_SBP}р') if float(card_turnover_SBP) >= 0 else self.turnover_SBP_num.setText(f'0р')
        self.balance_crypto_num.setText(f'{round(float(crypto_quantity), 5)} {crypto_data}')

        self.card_turnover_bar.setProperty("value", tools.set_percent(float(card_turnover), db.find_element('cards', ['number_card', card_name], 'name_bank'), False))        
        self.turnover_SBP_bar.setProperty("value", tools.set_percent(float(card_turnover_SBP), db.find_element('cards', ['number_card', card_name], 'name_bank'), True))

        #######################################
        cards = db.get_all_elements('cards', 'balance')
        balance = 0
        for item in cards:
            balance += float(item)

        set_balance = float(tools.read_csv('data/config.csv')[0][0])
        self.all_balance_fiat_num.setText(f'{balance}Р')
        self.current_income_num.setText(f'{balance - set_balance}') if balance - set_balance >= 0 else self.current_income_num.setText(f'0')

    def set_change(self):
        crypto_buy_name = self.crypto_buy_box.currentText()
        crypto_quantity_buy = db.find_element('crypto', ['name_crypto', crypto_buy_name], 'quantity') 
        self.label_5.setText(f'{round(float(crypto_quantity_buy), 5)}')

    def change_crypto(self):
        crypto_name_buy = self.crypto_buy_box.currentText()
        crypto_name_sell = self.crypto_sell_box.currentText()

        crypto_quantity_forward = float(self.enter_change_line.text())

        comission = float(tools.read_csv('data/config.csv')[1][0])
        crypto_quantity = tools.return_percent(crypto_quantity_forward, comission)

        if crypto_name_buy != crypto_name_sell:
            curse, sym = tools.combo_pair(crypto_name_buy, crypto_name_sell)
            if sym:
                quantity = crypto_quantity * curse
            else:
                quantity = crypto_quantity / curse

            self.label_6.setText(f'{round(float(quantity), 5)}')

            db.set_crypto(crypto_name_buy, quantity, 'minus')
            db.set_crypto(crypto_name_sell, quantity, 'plus')

            self.set_change()
            self.set_statistics()

    def addHistory(self, meaning):
        try:
            type = 'BUY' if meaning == 'buy' else 'SELL'
            crypto_name = self.crypto_buy_box.currentText() if meaning == 'buy' else self.crypto_sell_box.currentText()
            summ_fiat = self.summ_on_buy_enter.text() if meaning == 'buy' else f'{float(self.summ_on_sell_enter.text()) * float(self.enter_price_on_sell.text())}'
            price = self.enter_price_on_buy.text() if meaning == 'buy' else self.enter_price_on_sell.text()
            quantity_crypto = f'{float(self.summ_on_buy_enter.text()) / float(self.enter_price_on_buy.text())}' if meaning == 'buy' else self.enter_price_on_buy.text()
            bank = db.find_element('cards', ['number_card', self.card_for_buy_box.currentText()], 'name_bank') if meaning == 'buy' else db.find_element('cards', ['number_card', self.card_for_sell_box.currentText()], 'name_bank')
            sbp = True if self.use_SBP_buy_check.isChecked() and meaning == 'buy' else False
            third_face = True if self.third_party_check.isChecked() and meaning == 'sell' else False
            number_card = self.card_for_buy_box.currentText() if meaning == 'buy' else self.card_for_sell_box.currentText()

            db.add_history(type, crypto_name, summ_fiat, price, quantity_crypto, bank, number_card, sbp, third_face)
        except Exception as ex:
            print('Ошибка - ', ex)

