    def write_statistic_bank(self):
        list_status = db.get_all_elements('history', 'status')
        db_list_sbp = db.get_all_elements('history', 'is_sbp')
        db_list_third_face = db.get_all_elements('history', 'is_third_face')
        list_summ_fiat = db.get_all_elements('history', 'summ_fiat')

        quantity_list_buy = []
        quantity_list_sell = []
        medium_price_buy_list = []
        medium_price_sell_list = []
        list_sbp = []
        list_third_face = []

        [quantity_list_buy.append(item) if item == 'BUY' else quantity_list_sell.append(item) for item in list_status]
        [medium_price_buy_list.append(item) if item == 'BUY' else medium_price_sell_list.append(item) for item in list_summ_fiat]
        [list_sbp.append(item) if item == True else None for item in db_list_sbp]
        [list_third_face.append(item) if item == True else None for item in db_list_third_face]

        self.label_22.setText(str(len(quantity_list_buy)))
        self.label_25.setText(str(len(quantity_list_sell)))
        self.label_29.setText(str(len(list_sbp)))
        self.label_26.setText(str(len(list_third_face)))
        try:
            self.label_31.setText(f'{sum(medium_price_buy_list) / len(medium_price_buy_list)}')
            self.label_30.setText(f'{sum(medium_price_sell_list) / len(medium_price_sell_list)}')
        except:
            self.label_31.setText(f'0')
            self.label_30.setText(f'0')

    def show_statistic_card(self):
        name_bank = db.find_element('cards', ['number_card', self.comboBox.currentText()], 'name_bank')
        status = db.get_all_data(self.comboBox.currentText(), 'status')
        is_sbp = db.get_all_data(self.comboBox.currentText(), 'is_sbp')
        is_third_face = db.get_all_data(self.comboBox.currentText(), 'is_third_face')
        prices = db.get_all_data(self.comboBox.currentText(), 'price')
        print(name_bank, status, is_sbp, is_third_face, prices)
        list_buy = []
        price_buy = []
        
        list_sell = []
        price_sell = []
        for num_item in range(len(status)):
            if status[num_item] == "BUY":
                list_buy.append(status[num_item])
                price_buy.append(prices[num_item])
            elif status[num_item] == "SELL":
                list_sell.append(status[num_item])
                price_sell.append(status[num_item])
        
        self.label_12.setText(f'{len(list_buy)}')
        self.label_13.setText(f'{len(list_sell)}')
        self.label_14.setText(f'{len(is_sbp)}')
        self.label_17.setText(f'{len(is_third_face)}')
        try:
            self.label_18.setText(f'{sum(price_buy) / len(price_buy)}')
            self.label_20.setText(f'{sum(price_sell) / len(price_sell)}')
        except:
            pass

